    background-position: center;
    width: 100px;
    height: 100px;
    bottom: -40px;
    left: 40px;
    z-index: 1;
    opacity: 0.9;
}



#chat .avatar::before {
    content: '' !important;
    display: block !important;
    position: absolute !important;
    width: 90px !important;
    height: 90px !important;
    background-image: url('https://files.catbox.moe/afs4an.gif') !important;
    background-size: contain !important;
    background-repeat: no-repeat !important;
    background-position: center !important;
    z-index: 20 !important;
    pointer-events: none !important;


    top: 0 !important; 
}


#chat div[is_user="false"] .avatar::before {
    left: 220px; 
}
#chat div[is_user="true"] .avatar::before {
    right: 220px; 
}


#character_popup .avatar::before,
#user-settings-block .avatar::before,
#right-nav-panel .avatar::before {
    display: none !important;
}




div[is_user="true"] .ch_name {
    justify-content: flex-end !important;
}



div[is_user="true"] .ch_name > .flex-container {
    flex: 0 0 auto !important;
}
